import React, { useState } from 'react';
import { useNavigate, useLocation, useParams } from 'react-router-dom';

const KATEGORI = ["men's clothing", "women's clothing", 'electronics', 'jewelery'];

const formKosong = { title: '', price: '', category: "men's clothing", image: '', description: '' };

export default function FormProduk({ onSimpan, produkList }) {
  const navigate = useNavigate();
  const location = useLocation();
  const { id } = useParams();

  const produkEdit = location.state?.produk || produkList?.find(p => p.id === Number(id));
  const isEdit = !!produkEdit;

  const [form, setForm] = useState(
    isEdit
      ? { title: produkEdit.title, price: produkEdit.price, category: produkEdit.category, image: produkEdit.image, description: produkEdit.description }
      : formKosong
  );
  const [error, setError] = useState({});
  const [menyimpan, setMenyimpan] = useState(false);

  const ubahForm = (field, value) => {
    setForm(prev => ({ ...prev, [field]: value }));
    if (error[field]) setError(prev => { const baru = { ...prev }; delete baru[field]; return baru; });
  };

  const validasi = () => {
    const err = {};
    if (!form.title.trim()) err.title = 'Nama produk wajib diisi';
    if (!form.price || isNaN(form.price) || Number(form.price) <= 0) err.price = 'Harga harus lebih dari 0';
    return err;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const err = validasi();
    if (Object.keys(err).length > 0) { setError(err); return; }

    setMenyimpan(true);
    try {
      const payload = {
        title: form.title,
        price: Number(form.price),
        category: form.category,
        image: form.image || 'https://fakestoreapi.com/img/81fAn8jO4oL._AC_UX679_.jpg',
        description: form.description,
      };

      if (isEdit) {
        await onSimpan(produkEdit.id, payload);
      } else {
        await onSimpan(payload);
      }
      navigate('/');
    } catch {
      alert('Gagal menyimpan produk. Coba lagi.');
    } finally {
      setMenyimpan(false);
    }
  };

  return (
    <div className="halaman-form">
      <h1 className="judul-form">{isEdit ? 'Edit Produk' : 'Tambah Produk Baru'}</h1>
      <p className="subjudul-form">
        {isEdit ? 'Perbarui informasi produk di bawah ini.' : 'Isi form berikut untuk menambah produk baru.'}
      </p>

      <form className="form-produk" onSubmit={handleSubmit} noValidate>
        <div className="baris-form">
          <div className="grup-input">
            <label className="label-input">Nama Produk <span className="wajib">*</span></label>
            <input
              placeholder="Contoh: Jaket Denim Pria"
              value={form.title}
              onChange={e => ubahForm('title', e.target.value)}
              className={error.title ? 'error' : ''}
            />
            {error.title && <span className="pesan-error">{error.title}</span>}
          </div>

          <div className="grup-input">
            <label className="label-input">Harga (USD) <span className="wajib">*</span></label>
            <input
              type="number"
              step="0.01"
              min="0"
              placeholder="0.00"
              value={form.price}
              onChange={e => ubahForm('price', e.target.value)}
              className={error.price ? 'error' : ''}
            />
            {error.price && <span className="pesan-error">{error.price}</span>}
          </div>
        </div>

        <div className="baris-form">
          <div className="grup-input">
            <label className="label-input">Kategori</label>
            <select value={form.category} onChange={e => ubahForm('category', e.target.value)}>
              {KATEGORI.map(k => (
                <option key={k} value={k}>{k.charAt(0).toUpperCase() + k.slice(1)}</option>
              ))}
            </select>
          </div>

          <div className="grup-input">
            <label className="label-input">URL Gambar</label>
            <input
              placeholder="https://contoh.com/gambar.jpg"
              value={form.image}
              onChange={e => ubahForm('image', e.target.value)}
            />
          </div>
        </div>

        <div className="grup-input">
          <label className="label-input">Deskripsi</label>
          <textarea
            placeholder="Tulis deskripsi produk..."
            rows={4}
            value={form.description}
            onChange={e => ubahForm('description', e.target.value)}
          />
        </div>

        <div className="aksi-form">
          <button type="submit" className="tombol-simpan" disabled={menyimpan}>
            {menyimpan ? 'Menyimpan...' : isEdit ? 'Simpan Perubahan' : 'Tambah Produk'}
          </button>
          <button type="button" className="tombol-batal" onClick={() => navigate('/')}>
            Batal
          </button>
        </div>
      </form>
    </div>
  );
}
